return [
  { json: { url: 'https://circuitogastronomico.com.ar/category/novedades-eventos/feed/', source: 'Circuito Gastronómico', categoria: 'gastronomia', tipo: 'rss' } },
  { json: { url: 'https://cordobabeat.com/feed/', source: 'CBA Beat', categoria: 'electronica', tipo: 'rss' } }
];

const items = $input.all();
const result = [];
for (const item of items) {
  const xml = item.json.data || item.json.body || '';
  if (!xml) continue;
  const source = item.json.source || 'RSS';
  const categoria = item.json.categoria || 'cultura';
  const itemRegex = /<item>([\s\S]*?)<\/item>/gi;
  let match;
  while ((match = itemRegex.exec(xml)) !== null) {
    const block = match[1];
    const titleMatch = block.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>|<title>([^<]*)<\/title>/);
    const linkMatch = block.match(/<link>([^<]*)<\/link>|<guid[^>]*>([^<]*)<\/guid>/);
    const dateMatch = block.match(/<pubDate>([^<]*)<\/pubDate>/);
    const descMatch = block.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>|<description>([^<]*)<\/description>/);
    const titulo = (titleMatch?.[1] || titleMatch?.[2] || '').trim();
    const link = (linkMatch?.[1] || linkMatch?.[2] || '').trim();
    const fechaRaw = (dateMatch?.[1] || '').trim();
    const descripcion = (descMatch?.[1] || descMatch?.[2] || '').replace(/<[^>]+>/g, '').substring(0, 300).trim();
    if (titulo && link) {
      result.push({
        json: {
          titulo,
          fecha_original: fechaRaw,
          fecha_iso: fechaRaw ? new Date(fechaRaw).toISOString() : null,
          categoria,
          ubicacion: 'Córdoba',
          link,
          fuente: source,
          descripcion,
          fuente_tipo: 'rss'
        }
      });
    }
  }
}
return result.length > 0 ? result : [{ json: { _skip: true } }];

