const ahora = new Date();
const items = $input.all();

const validos = items
  .filter(item => {
    const e = item.json;
    if (!e.titulo) return false; 
    if (e._skip || e._empty) return false;

    if (e.fecha_iso) {
      try {
        const fecha = new Date(e.fecha_iso);
        if (isNaN(fecha.getTime())) return true;
        if (fecha < ahora) return false;
      } catch (err) {}
    }
    return true;
  })
  .map(item => ({
    json: {
      titulo: String(item.json.titulo || '').substring(0, 500),
      fecha_original: String(item.json.fecha_original || ''),
      fecha_iso: item.json.fecha_iso || null,
      categoria: String(item.json.categoria || 'cultura'),
      ubicacion: String(item.json.ubicacion || 'Córdoba').substring(0, 300),
      link: item.json.link ? String(item.json.link).substring(0, 1000) : '',
      fuente: String(item.json.fuente || 'Web').substring(0, 100),
      descripcion: String(item.json.descripcion || '').substring(0, 1000),
      fuente_tipo: String(item.json.fuente_tipo || 'http')
    }
  }));

// Schema versioning: alerta al admin si se extraen 0 eventos válidos
