const chatId = $input.first().json.chatId;
const text = $input.first().json.text;
if (!text || text.trim() === '') {
  return [{ json: { message: { text: 'Hola', chat: { id: chatId } } } }];
}
return [{ json: { message: { text: text, chat: { id: chatId } } } }];

const chatId = $input.first().json.message.chat.id;
const text = $input.first().json.message.text || '';
return [{ json: { chatId, text, originalMessage: $input.first().json.message } }];

// TP2 — Nodo: Detectar Comandos Especiales
// Intercepta /start, /help, /metrics antes del flujo de IA
const text = ($input.first().json.message?.text || '').trim();
const chatId = $input.first().json.message?.chat?.id;
const comando = text.split(' ')[0].toLowerCase();

const esComando = ['/start', '/help', '/metrics'].includes(comando);

return [{
  json: {
    ...($input.first().json),
    es_comando: esComando,
    comando: esComando ? comando : null
  }
}];

// TP2 — Generar respuesta para comandos especiales
const chatId = $input.first().json.message?.chat?.id;
const comando = $input.first().json.comando;

let texto = '';

if (comando === '/start') {
  texto = `👋 *¡Hola! Soy Colo*, tu asistente de eventos en Córdoba 🎉

Puedo ayudarte a encontrar eventos por:
• 🎭 *Categoría*: shows, electrónica, cultura, gastronomía, deportes
• 📅 *Cuándo*: hoy, este finde, esta semana, o una fecha específica
• 📍 *Dónde*: Güemes, Nueva Córdoba, Centro, etc.

*Ejemplos de consultas:*
\- "música este finde"
\- "teatro esta semana en el centro"
\- "gastronomía mañana"
\- "algo de cultura hoy en güemes"

Usá /help para ver todos los comandos disponibles.`;
} else if (comando === '/help') {
  texto = `ℹ️ *Comandos disponibles:*

/start — Bienvenida e instrucciones
/help — Esta ayuda
/metrics — Estadísticas del bot (solo admin)

*Cómo pedirme eventos:*
Podés combinar categoría + tiempo + zona en una sola frase:
\- "shows de electrónica este sábado en nueva córdoba"
\- "qué hay de gastronomía el viernes"
\- "deportes cerca del centro esta semana"

*Categorías disponibles:*
shows · electronica · cultura · gastronomia · deportes`;
} else if (comando === '/metrics') {
  texto = `📊 *Métricas del bot* (datos básicos via Telegram):

_Consultando estadísticas en tiempo real..._

⚠️ Para métricas completas, visitá el dashboard:
https://[TU-USUARIO].github.io/[TU-REPO]/`;
}

return [{ json: { chatId, texto_respuesta: texto, comando } }];

// TP2 — Clasificador de Intent (regex híbrido)
// Detecta: categoría + rango temporal + zona geográfica
// Si no detecta nada → marca como ambiguo para que el bot repregunta

const texto = ($input.first().json.message?.text || '').toLowerCase();
const tsInicio = Date.now();

// --- DIMENSIÓN 1: Categoría ---
const mapCategorias = {
  shows:       /show|recital|música|concierto|banda|teatro|obra|espectáculo|bailanta|cumbia|folkl/i,
  electronica: /electr|techno|dj|after|boliche|dance|minimal|house|trance/i,
  cultura:     /cultura|arte|expo|exposición|museo|galería|cine|film|feria|libro|taller|workshop/i,
  gastronomia: /gastronom|comida|restaurant|chef|cocina|fernet|cerveza|vino|food|bar de|bodega/i,
  deportes:    /deport|fútbol|básquet|tenis|running|maratón|crossfit|yoga|cycling|gym|cancha/i
};
let intent_categoria = null;
for (const [cat, regex] of Object.entries(mapCategorias)) {
  if (regex.test(texto)) { intent_categoria = cat; break; }
}

// --- DIMENSIÓN 2: Rango temporal ---
const mapFecha = {
  hoy:    /\bhoy\b|esta noche|ahorita|ahora/i,
  finde:  /fin de semana|finde|este sábado|este domingo|el sáb|el dom/i,
  semana: /esta semana|próximos días|próxima semana|los próximos|esta semana/i,
  puntual: /el \d{1,2}|\d{1,2}\/\d{1,2}|enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre/i
};
let intent_fecha = null;
for (const [tipo, regex] of Object.entries(mapFecha)) {
  if (regex.test(texto)) { intent_fecha = tipo; break; }
}

// --- DIMENSIÓN 3: Zona geográfica ---
const mapZonas = {
  'güemes':         /güemes|gúemes/i,
  'nueva córdoba':  /nueva cba|nueva córdoba|nueva cordoba|providencia/i,
  'centro':         /centro|cañada|plaza|san martín|independencia/i,
  'alberdi':        /alberdi/i,
  'cerro':          /cerro|las rosas|arguello/i,
  'costanera':      /costanera|río suquía/i,
  'villa allende':  /allende/i
};
let intent_zona = null;
for (const [zona, regex] of Object.entries(mapZonas)) {
  if (regex.test(texto)) { intent_zona = zona; break; }
}

// --- Determinar si es ambiguo (sin categoría Y sin fecha) ---
// Si no detectamos ni categoría ni fecha → el bot va a repreguntar
const intent_ambiguo = !intent_categoria && !intent_fecha;

return [{
  json: {
    ...($input.first().json),
    intent_categoria,
    intent_fecha,
    intent_zona,
    intent_ambiguo,
    ts_inicio: tsInicio
  }
}];
